import{_ as e,c as a,o as t,a4 as n}from"./chunks/framework.CzjLcc5X.js";const u=JSON.parse('{"title":"瑞士 -> 佛德州 -> 日內瓦湖(lac de Genève)","description":"","frontmatter":{},"headers":[],"relativePath":"瑞士/佛德州/日內瓦湖.md","filePath":"瑞士/佛德州/日內瓦湖.md","lastUpdated":1690748443000}'),r={name:"瑞士/佛德州/日內瓦湖.md"},o=n('<h1 id="日內瓦湖-lac-de-geneve" tabindex="-1">日內瓦湖(lac de Genève) <a class="header-anchor" href="#日內瓦湖-lac-de-geneve" aria-label="Permalink to &quot;日內瓦湖(lac de Genève)&quot;">​</a></h1><p><img src="https://i.imgur.com/BcDpzf1.jpg" alt="lac de Genève photo by Huang An Sheng"></p><p>萊芒湖(法語：lac Léman)，又稱日內瓦湖(lac de Genève)。湖北岸和東西兩端分屬瑞士佛德州、瓦萊州和日內瓦州，南岸則屬於法國上薩瓦省。瑞士和法國分別占有湖面的60%和40%。</p><p>日內瓦湖擁有很多「之最」: 氣候最溫和、湖泊面積最大，也是中歐水量最大的湖泊。</p><p>日內瓦湖區的航運也打破了紀錄。CGN航運公司擁有8艘輪槳蒸氣船，爲歐洲同類型船隊中最大。湖上的固定班次遊船把湖區很多村莊和城市連接起來。而被稱為Mouettes的小渡輪，則快速地將日內瓦的乘客從此岸送到彼岸。</p><h2 id="相關連結" tabindex="-1">相關連結 <a class="header-anchor" href="#相關連結" aria-label="Permalink to &quot;相關連結&quot;">​</a></h2><ul><li><a href="https://www.myswitzerland.com/zh-hant/destinations/lake-geneva/" target="_blank" rel="noreferrer">瑞士國家旅遊局 - 日內瓦湖</a></li></ul>',7),c=[o];function l(s,_,d,i,p,h){return t(),a("div",null,c)}const f=e(r,[["render",l]]);export{u as __pageData,f as default};
